// ─── Waiter Calls ─────────────────────────────────────────────────────────────
export const getWaiterCalls  = (): WaiterCall[] => get(KEYS.calls, []);
export const saveWaiterCalls = (c: WaiterCall[]) => set(KEYS.calls, c);

export function addWaiterCall(tableId: number, message: string, customerName?: string): void {
  const calls = getWaiterCalls();
  calls.push({
    id: `CALL-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    tableId, customerName, message,
    timestamp: new Date().toISOString(),
    resolved: false,
  });
  saveWaiterCalls(calls);
}

export function resolveWaiterCall(callId: string, by?: string): void {
  const calls = getWaiterCalls();
  const idx = calls.findIndex(c => c.id === callId);
  if (idx === -1) return;
  calls[idx].resolved   = true;
  calls[idx].resolvedAt = new Date().toISOString();
  calls[idx].resolvedBy = by;
  saveWaiterCalls(calls);
}

// ─── Analytics helpers ────────────────────────────────────────────────────────
export function getOrdersInPeriod(period: 'today'|'week'|'month'|'all'): Order[] {
  const all = getOrders();
  const now = new Date();
  return all.filter(o => {
    if (o.status === 'cancelled') return false; // exclude cancelled from revenue
    const d = new Date(o.timestamp);
    if (period === 'today') return d.toDateString() === now.toDateString();
    if (period === 'week')  { const s=new Date(now); s.setDate(now.getDate()-now.getDay()); s.setHours(0,0,0,0); return d>=s; }
    if (period === 'month') return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth();
    return true;
  });
}

// ─── CSV Export ───────────────────────────────────────────────────────────────
export function exportOrdersCSV() {
  const orders = getOrders();
  if (!orders.length) { alert('No orders to export.'); return; }

  const DAY   = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const MONTH = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const PAY:Record<string,string> = { paytm:'Paytm', phonepe:'PhonePe', gpay:'Google Pay', cod:'Cash' };

  const headers = ['Order ID','Date','Time','Day','Week No.','Month','Year','Customer','Phone','Type','Table/Pickup','Staff','Item Name','Item Qty','Unit Price (₹)','Line Total (₹)','Subtotal (₹)','Discount (₹)','Discount Reason','Total (₹)','Payment','Status','Cancel Reason'];
  const rows: (string|number)[][] = [];

  orders.forEach(order => {
    const d    = new Date(order.timestamp);
    const date = `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
    const time = d.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
    const loc  = order.type==='dine-in'?`Table ${order.tableId}`:'Pickup';
    const pay  = PAY[order.payment]??order.payment??'';
    const items= order.items??[];

    if (!items.length) {
      rows.push([order.id,date,time,DAY[d.getDay()],Math.ceil(d.getDate()/7),MONTH[d.getMonth()],d.getFullYear(),order.customerName,order.phone??'',order.type,loc,order.staffName??'','','','','',order.subtotal,order.discount??0,order.discountReason??'',order.total,pay,order.status,order.cancelReason??'']);
    } else {
      items.forEach((item,i)=>{
        const line=item.subtotal??(item.price*item.qty);
        rows.push([i===0?order.id:'',i===0?date:'',i===0?time:'',i===0?DAY[d.getDay()]:'',i===0?Math.ceil(d.getDate()/7):'',i===0?MONTH[d.getMonth()]:'',i===0?d.getFullYear():'',i===0?order.customerName:'',i===0?(order.phone??''):'',i===0?order.type:'',i===0?loc:'',i===0?(order.staffName??''):'',item.name,item.qty,item.price,line,i===0?order.subtotal:'',i===0?(order.discount??0):'',i===0?(order.discountReason??''):'',i===0?order.total:'',i===0?pay:'',i===0?order.status:'',i===0?(order.cancelReason??''):'']);
      });
    }
  });

  const esc=(v:string|number)=>{const s=String(v??'');return(s.includes(',')||s.includes('"')||s.includes('\n'))?`"${s.replace(/"/g,'""')}"`:s;};
  const csv=[headers,...rows].map(r=>r.map(esc).join(',')).join('\n');
  const blob=new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const now=new Date();
  const fname=`FoodieLover_${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}.csv`;
  const a=document.createElement('a');a.href=url;a.download=fname;
  document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);
}
